        $results = Test-SecretRotation -Secrets $secrets -ReferenceDate $refDate -WarningDays 14
        $ok = $results | Where-Object { $_.status -eq 'ok' }
        $ok | Should -HaveCount 1
        $ok[0].name | Should -Be 'OK_SECRET'
    }

