        # WARNING: rotated 2026-04-15 + 30 days = 2026-05-15, ref 2026-05-07 => 8 days
        $warning = $results | Where-Object { $_.name -eq 'WARNING' }
        $warning.daysUntilExpiry | Should -Be 8
    }

