        $testResults = @(
            [PSCustomObject]@{ name = 'SEC_A'; status = 'expired'; daysUntilExpiry = -10; expiryDate = [datetime]'2026-04-27'; requiredBy = @('svc-1','svc-2'); rotationPolicyDays = 30 }
